const DEFAULT_RESOLVE_URL = 'https://us-central1-node-red-alerts.cloudfunctions.net/firmware_httpResolveRelease';
const DEFAULT_ALIASES = {};

const rawTarget = String(msg.firmwareTarget || msg.req?.params?.target || msg.req?.query?.target || 'mcu').trim();
const normalized = rawTarget.toLowerCase();
const requestedTarget = normalized === '12b' ? '12B' : normalized === '12m' ? '12M' : 'mcu';
const configuredAliases = flow.get('firmwareTargetAliases');
const aliases = configuredAliases && typeof configuredAliases === 'object'
    ? configuredAliases
    : DEFAULT_ALIASES;
const target = aliases[requestedTarget] || requestedTarget;

msg._firmwareRequestedTarget = requestedTarget;
msg._firmwareTarget = target;
msg.method = 'POST';
msg.url = String(flow.get('firmwareResolveUrl') || DEFAULT_RESOLVE_URL).trim() || DEFAULT_RESOLVE_URL;
msg.headers = {
    'Content-Type': 'application/json'
};
msg.payload = {
    data: { target }
};

node.status({
    fill: 'blue',
    shape: 'dot',
    text: requestedTarget === target ? `Resolving ${target}` : `Resolving ${requestedTarget}->${target}`
});
return msg;

const target = msg._firmwareTarget || 'mcu';
const requestedTarget = msg._firmwareRequestedTarget || target;
const body = msg.payload || {};
const result = body && typeof body.result === 'object' ? body.result :
    body && typeof body.data === 'object' ? body.data :
    body;

function fail(statusCode, message, extra) {
    msg.statusCode = statusCode;
    msg.headers = {
        'Content-Type': 'application/json; charset=utf-8',
        'Cache-Control': 'no-store'
    };
    msg.payload = Object.assign({
        code: statusCode,
        type: 0,
        data: '',
        msg: message,
        time: Date.now(),
        target,
        requestedTarget
    }, extra || {});
    node.status({ fill: 'red', shape: 'ring', text: requestedTarget + '->' + target + ': ' + message });
    return msg;
}

function getHeader(name) {
    const headers = msg.req && msg.req.headers ? msg.req.headers : {};
    const value = headers[String(name || '').toLowerCase()] || headers[name];
    return Array.isArray(value) ? value[0] : String(value || '').trim();
}

function getPublicBaseUrl() {
    let configured = String(flow.get('firmwarePublicBaseUrl') || '').trim();
    while (configured.endsWith('/')) {
        configured = configured.slice(0, -1);
    }
    if (configured) return configured;

    const host = getHeader('host');
    if (!host) return '';

    const forwardedProto = getHeader('x-forwarded-proto').split(',')[0].trim();
    const proto = forwardedProto || 'http';
    return proto + '://' + host;
}

function parseFirmwareData(data) {
    const parts = String(data || '').split(',');
    const fileName = String(parts.shift() || '').trim();
    const size = Number(String(parts.shift() || '').trim());
    const signedUrl = parts.join(',').trim();
    return { fileName, size, signedUrl };
}

function pruneCache(cache, now) {
    Object.keys(cache || {}).forEach((key) => {
        const item = cache[key];
        if (!item || Number(item.expiresAt || 0) <= now) {
            delete cache[key];
        }
    });
    return cache || {};
}

if (body.error) {
    return fail(Number(msg.statusCode || 500), body.error.message || body.error.status || 'Firmware resolver error', {
        error: body.error
    });
}

if (!result || Number(result.code) !== 200 || !result.data) {
    return fail(502, 'No active firmware metadata returned', {
        resolverPayload: result || null
    });
}

const parsed = parseFirmwareData(result.data);
const release = result.release || {};
const releaseId = String(release.id || '').trim();
const fileName = String(release.fileName || parsed.fileName || '').trim();
const size = Number(release.size || parsed.size || 0);
const signedUrl = parsed.signedUrl;

if (!fileName || !Number.isFinite(size) || size <= 0 || !signedUrl) {
    return fail(502, 'Firmware metadata is missing filename, size, or URL', {
        resolverPayload: result || null
    });
}

let deliveryUrl = signedUrl;
const useLocalProxy = flow.get('firmwareUseLocalProxy') !== false;
if (useLocalProxy) {
    if (!releaseId) {
        return fail(502, 'Firmware resolver did not return release id', {
            resolverPayload: result || null
        });
    }

    const publicBaseUrl = getPublicBaseUrl();
    if (!publicBaseUrl) {
        return fail(500, 'Set flow.firmwarePublicBaseUrl or call this endpoint with a Host header');
    }

    const now = Date.now();
    const cache = pruneCache(flow.get('firmwareProxyCache') || {}, now);
    cache[releaseId] = {
        target,
        requestedTarget,
        releaseId,
        fileName,
        size,
        signedUrl,
        cachedAt: now,
        expiresAt: now + (55 * 60 * 1000)
    };
    flow.set('firmwareProxyCache', cache);

    deliveryUrl = publicBaseUrl + '/firmware/proxy/' + encodeURIComponent(target) + '/' + encodeURIComponent(releaseId) + '/' + encodeURIComponent(fileName);
}

msg.statusCode = 200;
msg.headers = {
    'Content-Type': 'application/json; charset=utf-8',
    'Cache-Control': 'no-store'
};
msg.payload = {
    code: 200,
    type: Number(result.type || 0),
    data: fileName + ',' + size + ',' + deliveryUrl,
    msg: result.msg || 'ok',
    time: Number(result.time || Date.now())
};

const statusPrefix = requestedTarget === target ? target : requestedTarget + '->' + target;
node.status({ fill: 'green', shape: 'dot', text: statusPrefix + ': ' + fileName + (useLocalProxy ? ' via proxy' : ' direct') });
return msg;

const message = msg.error?.message || 'Firmware endpoint failed';
msg.statusCode = 500;
msg.headers = {
    'Content-Type': 'application/json; charset=utf-8',
    'Cache-Control': 'no-store'
};
msg.payload = {
    code: 500,
    type: 0,
    data: '',
    msg: message,
    time: Date.now(),
    target: msg._firmwareTarget || msg.firmwareTarget || ''
};
node.status({ fill: 'red', shape: 'ring', text: message });
return msg;

const DEFAULT_RESOLVE_URL = 'https://us-central1-node-red-alerts.cloudfunctions.net/firmware_httpResolveRelease';
const DEFAULT_ALIASES = {};

function normalizeTarget(value) {
    const normalized = String(value || 'mcu').trim().toLowerCase();
    if (normalized === '12b') return '12B';
    if (normalized === '12m') return '12M';
    return 'mcu';
}

function fail(statusCode, message) {
    msg.statusCode = statusCode;
    msg._firmwareProxyError = message;
    return [null, null, msg];
}

const params = msg.req && msg.req.params ? msg.req.params : {};
const requestedTarget = normalizeTarget(params.target || 'mcu');
const configuredAliases = flow.get('firmwareTargetAliases');
const aliases = configuredAliases && typeof configuredAliases === 'object' ? configuredAliases : DEFAULT_ALIASES;
const target = aliases[requestedTarget] || requestedTarget;
const releaseId = String(params.releaseId || '').trim();
const fileName = String(params.fileName || '').trim();

if (!releaseId || !fileName) {
    return fail(400, 'Missing firmware releaseId or fileName');
}

const now = Date.now();
const cache = flow.get('firmwareProxyCache') || {};
const cached = cache[releaseId];
msg._firmwareProxy = {
    requestedTarget,
    target,
    releaseId,
    fileName,
    size: cached && Number(cached.size || 0) || 0
};

if (cached && cached.signedUrl && String(cached.target || '') === target && String(cached.fileName || '') === fileName && Number(cached.expiresAt || 0) > now + 60000) {
    msg.method = 'GET';
    msg.url = cached.signedUrl;
    msg.headers = {};
    msg.payload = null;
    node.status({ fill: 'blue', shape: 'dot', text: 'Proxy cached ' + target + ': ' + fileName });
    return [msg, null, null];
}

msg.method = 'POST';
msg.url = String(flow.get('firmwareResolveUrl') || DEFAULT_RESOLVE_URL).trim() || DEFAULT_RESOLVE_URL;
msg.headers = {
    'Content-Type': 'application/json'
};
msg.payload = {
    data: { target }
};
node.status({ fill: 'blue', shape: 'ring', text: 'Proxy resolving ' + target });
return [null, msg, null];

const info = msg._firmwareProxy || {};
const body = msg.payload || {};
const result = body && typeof body.result === 'object' ? body.result :
    body && typeof body.data === 'object' ? body.data :
    body;

function fail(statusCode, message, extra) {
    msg.statusCode = statusCode;
    msg._firmwareProxyError = message;
    if (extra) msg._firmwareProxyExtra = extra;
    return [null, msg];
}

function parseFirmwareData(data) {
    const parts = String(data || '').split(',');
    const fileName = String(parts.shift() || '').trim();
    const size = Number(String(parts.shift() || '').trim());
    const signedUrl = parts.join(',').trim();
    return { fileName, size, signedUrl };
}

if (body.error) {
    return fail(Number(msg.statusCode || 500), body.error.message || body.error.status || 'Firmware resolver error', body.error);
}

if (!result || Number(result.code) !== 200 || !result.data) {
    return fail(502, 'No active firmware metadata returned', result || null);
}

const parsed = parseFirmwareData(result.data);
const release = result.release || {};
const releaseId = String(release.id || '').trim();
const fileName = String(release.fileName || parsed.fileName || '').trim();
const size = Number(release.size || parsed.size || 0);
const signedUrl = parsed.signedUrl;

if (releaseId && info.releaseId && releaseId !== info.releaseId) {
    return fail(409, 'Firmware release changed before proxy download: expected ' + info.releaseId + ', current ' + releaseId);
}

if (info.fileName && fileName && fileName !== info.fileName) {
    return fail(409, 'Firmware filename changed before proxy download: expected ' + info.fileName + ', current ' + fileName);
}

if (!signedUrl || !fileName || !Number.isFinite(size) || size <= 0) {
    return fail(502, 'Resolved firmware metadata is missing filename, size, or URL', result || null);
}

const now = Date.now();
const cache = flow.get('firmwareProxyCache') || {};
cache[info.releaseId || releaseId] = {
    target: info.target || result.target || 'mcu',
    requestedTarget: info.requestedTarget || info.target || result.target || 'mcu',
    releaseId: info.releaseId || releaseId,
    fileName,
    size,
    signedUrl,
    cachedAt: now,
    expiresAt: now + (55 * 60 * 1000)
};
flow.set('firmwareProxyCache', cache);

msg._firmwareProxy = Object.assign({}, info, {
    releaseId: info.releaseId || releaseId,
    fileName,
    size
});
msg.method = 'GET';
msg.url = signedUrl;
msg.headers = {};
msg.payload = null;
node.status({ fill: 'blue', shape: 'dot', text: 'Proxy download ' + fileName });
return [msg, null];

const info = msg._firmwareProxy || {};
const statusCode = Number(msg.statusCode || 200);

function safeFileName(value) {
    return String(value || 'firmware.bin').split('').map((ch) => {
        const code = ch.charCodeAt(0);
        return ch === '"' || ch === '\\' || code === 10 || code === 13 ? '_' : ch;
    }).join('');
}

if (statusCode >= 400) {
    msg.statusCode = statusCode;
    msg.headers = {
        'Content-Type': 'text/plain; charset=utf-8',
        'Cache-Control': 'no-store'
    };
    msg.payload = Buffer.isBuffer(msg.payload) ? msg.payload.toString('utf8') : String(msg.payload || 'Firmware download failed');
    return msg;
}

msg.statusCode = 200;
msg.headers = {
    'Content-Type': 'application/octet-stream',
    'Content-Disposition': 'attachment; filename="' + safeFileName(info.fileName) + '"',
    'Cache-Control': 'no-store'
};

if (Buffer.isBuffer(msg.payload)) {
    msg.headers['Content-Length'] = String(msg.payload.length);
}

node.status({ fill: 'green', shape: 'dot', text: 'Served ' + safeFileName(info.fileName) });
return msg;

const message = msg._firmwareProxyError || msg.error && msg.error.message || 'Firmware proxy failed';
msg.statusCode = Number(msg.statusCode || 500);
msg.headers = {
    'Content-Type': 'text/plain; charset=utf-8',
    'Cache-Control': 'no-store'
};
msg.payload = message;
node.status({ fill: 'red', shape: 'ring', text: message });
return msg;
